class Solution:
    def superEggDrop(self, k: int, n: int) -> int:
        # O(k * n * log n) via standard DP with binary search over drop floor
        # dp[eggs][floors] = min moves; build bottom-up
        dp = list(range(n + 1))  # base: 1 egg needs j drops for j floors
        for eggs in range(2, k + 1):
            new_dp = [0] * (n + 1)
            x = 1
            for floors in range(1, n + 1):
                # optimal drop floor x is non-decreasing as floors grows
                while x < floors and max(dp[x - 1], new_dp[floors - x]) > max(dp[x], new_dp[floors - x - 1]):
                    x += 1
                new_dp[floors] = 1 + max(dp[x - 1], new_dp[floors - x])
            dp = new_dp
        return dp[n]

solutions.javascript:
var superEggDrop = function(k, n) {
    // f(t, k) = max floors certifiable in t moves with k eggs
    // recurrence: f(t,k) = f(t-1,k-1) + f(t-1,k) + 1
    let dp = new Array(k + 1).fill(0);
    let t = 0;
    while (dp[k] < n) {
        t++;
        const newDp = new Array(k + 1).fill(0);
        for (let j = 1; j <= k; j++) {
            newDp[j] = dp[j - 1] + dp[j] + 1;
        }
        dp = newDp;
    }
    return t;
};
